import React from 'react';

const Home = () => {
  return (
    <div style={{ fontFamily: 'Arial, sans-serif', backgroundColor: '#f9f9f9', padding: '10px' }}>
      {/* Header */}
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '20px' }}>
        <img src='/logo.png' alt='Tezro' width='80' />
        <div style={{ fontSize: '14px', fontWeight: 'bold' }}>PKR 2,450</div>
      </div>

      {/* Tracking Card */}
      <div style={{ background: '#fff', padding: '15px', borderRadius: '10px', border: '1px solid #ddd', marginBottom: '20px' }}>
        <input type='text' placeholder='Track, Book or Search Shipment...' style={{ width: '100%', padding: '10px', borderRadius: '5px', border: '1px solid #ccc' }} />
      </div>

      {/* Categories Grid */}
      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(5, 1fr)', gap: '10px', marginBottom: '20px' }}>
        {['Domestic', 'Air', 'Cargo', 'Road', 'Storage'].map((item) => (
          <div key={item} style={{ textAlign: 'center', fontSize: '10px' }}>
            <div style={{ background: '#eee', padding: '10px', borderRadius: '5px' }}>🚚</div>
            {item}
          </div>
        ))}
      </div>

      {/* Quick Actions */}
      <div style={{ background: '#fff', padding: '15px', borderRadius: '10px' }}>
        <h3>Quick Actions</h3>
        <div style={{ display: 'flex', justifyContent: 'space-between' }}>
          {['Track', 'Calculator', 'Pickup'].map((action) => (
            <button style={{ padding: '10px', border: 'none', background: '#000', color: '#fff', borderRadius: '5px' }}>{action}</button>
          ))}
        </div>
      </div>
    </div>
  );
};
export default Home;
